use std::sync::{Arc, Mutex, RwLock};
use std::thread;
use std::collections::HashMap;

#[derive(Debug)]
pub struct Inventory {
    items: RwLock<HashMap<String, i32>>,
}

impl Inventory {
    pub fn new() -> Self {
        Inventory {
            items: RwLock::new(HashMap::new()),
        }
    }

    pub fn add_item(&self, name: String, quantity: i32) {
        self.items.write().unwrap().insert(name, quantity);
    }

    pub fn check_stock(&self, name: &str) -> i32 {
        *self.items.read().unwrap().get(name).unwrap_or(&0)
    }

    pub fn decrement_stock(&self, name: &str, quantity: i32) -> bool {
        let mut items = self.items.write().unwrap();
        match items.get_mut(name) {
            Some(stock) => {
                if *stock >= quantity {
                    *stock -= quantity;
                    true
                } else {
                    false
                }
            }
            None => false,
        }
    }
}

pub fn concurrent_inventory_update(
    inventory: Arc<Inventory>,
    updates: Vec<(String, i32)>,
    num_threads: usize,
) {
    let mut handles = vec![];
    let chunk_size = updates.len() / num_threads;
    
    for chunk in updates.chunks(chunk_size) {
        let inventory_clone = Arc::clone(&inventory);
        let chunk = chunk.to_vec();
        
        let handle = thread::spawn(move || {
            for (item, quantity) in chunk {
                inventory_clone.decrement_stock(&item, quantity);
            }
        });
        
        handles.push(handle);
    }
    
    for handle in handles {
        handle.join().unwrap();
    }
}